INSERT INTO "public"."books" ("id", "title", "description", "price", "author", "image", "format", "pages", "bookBinding", "isbn", "resume", "especiality", "state", "dateUpload") VALUES
(1, 'Manual de fisioterapia en pequeños animales', 'Este Manual de fisioterapia en pequeños animales recopila las bases teóricas y la experiencia clínica de reconocidos especialistas en fisioterapia y rehabilitación veterinaria.', 1, 'F. Minguell, G. Sterin, C. García, A. Ramón, A. Calzada, M. Pérez, F. Miró, I. Montes, S. Martí', 'e7a3008b8e164aa6ca8b61af5e89953fc7469f218fd446f150329d6f7e2882db.webp', '17 x 24 cm', 670, 'tapa dura', '978-84-96344-03-7', 'Este Manual de fisioterapia en pequeños animales recopila las bases teóricas y la experiencia clínica de reconocidos especialistas en fisioterapia y rehabilitación veterinaria. Desde una visión científica y práctica permitirá a los profesionales veterinarios conocer el potencial terapéutico de cada una de las técnicas y aplicar en cada caso las técnicas más adecuadas. Incluye, además del amplio abanico de las terapias manuales y técnicas de fisioterapia, una introducción a las terapias o medicinas no-convencionales a través de una visión científica y clínica, porque en nuestra opinión representan una notable ayuda tanto en el diagnóstico como en el tratamiento y, sobre todo en la concepción holística del individuo. Esta visión permite no solo tratar y prevenir una serie de patologías sino que pretende que cada individuo encuentre su equilibrio y una mejor calidad de vida.', '["fisioterapia", "rehabilitacion veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(2, 'Nefrología y urología canina y felina', 'Este libro se ha pensado para su uso por parte de estudiantes, recién licenciados, y veterinarios que quieran revisar las alteraciones del sistema urinario, aún cuando tiene valor para los especialistas y residentes de medicina interna.', 1, 'Dennis J. Chew', '5f85aa673bfe6a408a25d93fe9cb4b39a6902484583ff3e579a372ff89d37568.webp', '17 x 24 cm', 680, 'tapa dura', '978-84-96344-39-6', '¡Diagnostique y trate las enfermedades y alteraciones del tracto urinario de forma rápida y precisa! Localice fácilmente la información que necesita para prevenir y manejar de la forma más efectiva las condiciones renales y vesicales en perros y gatos. Combinando un entendimiento experto y un contenido basado en evidencias en una presentación clara y concisa, este manual le mantendrá actualizado en las prácticas más recientes y le ayudará a manejar con confianza la creciente incidencia de las complicaciones del tracto urinario en pequeños animales. Descripción basada en evidencias de los temas candentes: refleja la información clínica actual y le ayuda a proveer el cuidado al paciente más efectivo. Formato convenientemente destacado con contenido conciso y clínicamente enfocado: facilita encontrar la información que se precisa. Algoritmos, FAQs, y recomendaciones del manejo de casos: Aporta consejos y directrices clínicamente prácticas. Cuadros especiales Información clave resaltada a vista. Descripción directa de la fisiopatología del tracto renal y urinario inferior: aporta un trasfondo esencial para la aplicación clínica.', '["nefrologia", "urologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(3, 'Manual práctico de medicina felina', 'Esta obra, editada por 3 Médicos Veterinarios dedicados a la Medicina Felina, ha sido escrita por un elenco de 31 Médicos Veterinarios de distintos países de habla hispana, lo que permite que en la misma se integren perspectivas de realidades distintas, manteniéndose las temáticas dentro de las particularidades halladas por el lector en su práctica habitual.', 1, 'Fabián G. Minovich, Alicia M. Rubio, Lina Sanz', '4fb1fd7c51dfc771e8c48da035b65f14a3bb27470c3ccc3783f8e5710458c024.webp', '17 x 24 cm', 552, 'tapa dura', '978-84-96344-88-4', 'El objetivo es otorgar una actualización de las principales enfermedades y problemas de manejo que la especie felina presenta, de una manera sencilla y didáctica. Dentro de los fines principales de la obra, está el otorgarle a los Médicos Veterinarios temas que abarcan desde causas y manejo de la obesidad, anorexia y anemia hasta el desarrollo de enfermedades y patologías complejas como la enfermedad renal crónica, pancreatitis, uveítis, hipertensión, peritonitis infecciosa felina y retrovirosis, entre otras. Se presenta un marco teórico de cada tema, para luego abordar las técnicas recomendadas de diagnóstico y terapéutica disponibles. La obra cuenta con figuras, tablas y esquemas que permiten una mejor comprensión y análisis de los temas descritos, que son en su mayoría temas habituales de consulta en la clínica de felinos.', '["medicina felina"]', 'active', '2025-10-15 23:18:01.565696+00'),
(4, 'Abordaje terapéutico de las intoxicaciones en pequeños animales', 'Abordaje terapéutico de las intoxicaciones en pequeños animales brinda al lector temas actualizados referidos a las principales intoxicaciones que afectan a caninos y felinos. En algunos casos se mencionan también aquellos tóxicos que afectan a mascotas no convencionales.', 1, 'Pedro Zeinsteger', 'e863c63e8caf1def5ef429ea209b345bacebb5fa6fa7849578a50177ffe78269.webp', '17 x 24 cm', 368, 'tapa dura', '978-84-96344-89-1', 'Propone en cada tema, un abordaje teórico inicial de conceptos básicos y específicos a modo de repaso y contextualización, para luego indicar las maniobras destinadas a determinar el agente tóxico involucrado, signología asociada y terapéuticas generales y específicas para el tratamiento de las intoxicaciones más frecuentes en pequeñas especies. En su escritura se ha considerado el siguiente organigrama: • Características fisicoquímicas generales que son inherentes a los tóxicos. • Sus mecanismos de acción (toxicodinamia) y los procesos que sufre durante su paso por el organismo (toxicocinética). • Signología clínica general y específica asociada a los efectos tóxicos. • Pruebas convencionales que puede ofrecer el laboratorio para realizar estudios complementarios que permitan al clínico acercarse al diagnóstico. • Pruebas específicas del laboratorio de toxicología, para intentar llegar al diagnóstico etiológico. • Tratamiento signológico y, en aquellos casos en que estén disponibles, la indicación de antídotos específicos.', '["toxicologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(5, 'Casos clínicos de medicina felina', 'Este libro es una recopilación de casos clínicos típicos en medicina felina, estudiados hasta el diagnóstico definitivo. A través de ellos, se recorren desde pruebas diagnósticas habituales hasta cirugías complejas, con un enfoque metódico y estructurado..', 1, 'Salvador Cervantes', '4303c070e5d8d4e4d7c813f636b712fbc302f2a534af74b9c7ad6e7c95ad115b.webp', '17 x 24 cm', 240, 'tapa dura', '978-84-18636-32-5', 'Pensado para veterinarios en diferentes etapas de su carrera, es una herramienta útil tanto para estudiantes de últimos años como para clínicos generalistas que desean perfeccionar su “diagnostic approach” en gatos. También es ideal para profesionales con una base sólida en medicina interna, pero con mayor experiencia en perros, que quieran adentrarse en la medicina felina con seguridad y rigor.', '["medicina felina", "casos clinicos"]', 'active', '2025-10-15 23:18:01.565696+00'),
(6, 'Cardiología clínica en el perro y en el gato', 'La cardiología es una especialidad clínica que requiere un amplio conocimiento de múltiples áreas de la medicina. Estos conocimientos abarcan desde anatomía, fisiología, técnicas de imagen y electrocardiografía, hasta la cirugía y técnicas de mínima invasión, conviritendo a esta especialidad, sin duda, en una de las más complejas y complicadas.', 1, 'D. M. Porteiro, A. J. Santana', '541dbc94448c8eef2a8e489d9a1704e10e25ddf352d220b19142f650f2e253a1.webp', '22 x 28 cm', 384, 'tapa dura', '978-84-96344-97-6', 'En esta obra, los autores y colaboradores se han esforzado en plasmar de forma clara la teoría y práctica que tanto el clínico generalista, como el clínico con especial interés en el área, deben conocer. Cabe destacar que la obra ha sido realizada por veterinarios referentes en este área con un gran conocimiento y experiencia clínica, lo que la dota de gran facilidad para la lectura, comprensión y asimilación de los conocimientos, priorizando y ampliando aquellos que bajo su criterio profesional son de especial relevancia para el día a día. Con esta obra el lector obtendrá: • conocimientos anatómicos, fisiológicos y de fisiopatología básicos y necesarios para el correcto aprendizaje • capacidad para realizar una correcta exploración, abordaje diagnóstico y terapéutico, así como establecer pronósticos y seguimientos de las principales patologías cardíacas • amplios conocimientos de las principales pruebas diagnósticas, con capítulos como ecocardiografía, radiología y electgrocardiografía, donde el lector podrá aprender cómo realizar e interpretar dichas pruebas • explicación de técnicas quirúrgicas avanzadas en el área de cirugía cardíaca', '["cardiologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(7, 'Manual de protocolos de anestesia en perros, gatos y exóticos', 'La anestesia es una disciplina médica que permite realizar procedimientos invasivos en los pacientes pero que no está exenta de riesgos potencialmente peligrosos para la vida del animal. Se trata, además, de una especialidad de la medicina veterinaria que ha evolucionado enormemente en las últimas dos décadas, buscando los procedimientos más eficaces y seguros posibles con el mínimo dolor tolerable.', 1, 'Juan Salom, Gaspar Soler', 'edc1058b3eef61ab550deb1daa1ea5e4735a890f4dd153d460479a8a6ee7ce94.webp', '17 x 24 cm', 256, 'tapa dura', '978-84-18636-18-9', 'Para conseguir estos objetivos son necesarios extensos conocimientos de fisiopatología, farmacología y formación acerca del uso de maquinaria muy técnica y específica. Esta obra pretende convertirse en un apoyo útil, completo y actualizado, que ayude al lector a desenvolverse con soltura tanto en los procedimientos más rutinarios como en aquellos más específicos o complejos, sirviéndose de la experiencia de los autores junto con los conocimientos y publicaciones más actuales. Siguiendo la misma línea del Manual de protocolos de urgencia en pequeños animales, se trata de una obra de consulta rápida con información concisa y protocolaria para poder realizar múltiples procedimientos anestésicos y analgésicos y ayudar a tomar las decisiones más adecuadas ante las principales complicaciones que puedan aparecer.', '["anestesia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(8, 'Emergencias y cuidados críticos en pequeños animales, 2ª edición', 'Emergencias y cuidados críticos en pequeños animales 2ª edición tiene como misión ofrecer al profesional y estudiante de veterinaria de habla hispana un compendio accesible y práctico, pero sin perder de vista las bases teóricas para comprender y realizar mejores prácticas médicas.', 1, 'Javier Mouly', '8795bd09e3b7ba6b1bbd2df0f896dc4bc5702d286549b0cd4b259ca64bad7bf1.webp', '22 x 28 cm', 848, 'tapa dura', '978-84-18636-19-6', 'Dentro de los objetivos puntuales de la obra se destacan: • Identificar la secuencia correcta de prioridades a seguir en la atención médica quirúrgica del paciente crítico y en urgencias. • Comprender la fisiopatología de situaciones críticas para poder interpretar los signos clínicos y dirigir métodos complementarios y de monitoreo, de esta manera abordar con conocimientos sólidos al paciente crítico y en urgencias. • Esquematizar los exámenes primario y secundario que se deben efectuar en la evaluación integral del paciente crítico y en urgencias. • Explicar y poner en práctica las diferentes técnicas, previo marco teórico, con el fin de abordar al paciente crítico. • Aportar los tratamientos de elección en cada patología tratada.', '["emergencias veterinarias", "cuidados criticos"]', 'active', '2025-10-15 23:18:01.565696+00'),
(9, 'Manual práctico de medicina felina volumen II', 'Este Manual de Medicina Felina Práctica, editado por 3 Médicos Veterinarios, reconocidos internacionalmente y escrito por 50 excelentes profesionales de distintos países de habla hispana, es una guía indispensable para todos aquellos Veterinarios que desarrollan su actividad en contacto con el gato.', 1, 'Fabián Minovich, Alicia Rubio, Lina Sanz', 'ea31bdd0bf600e5e4b34d667443dcc9da34ce18c607b622e87d81e9a426de468.webp', '17 x 24 cm', 560, 'tapa dura', '978-84-18636-22-6', 'En estas páginas, encontrarán desde los primeros signos de enfermedad hasta la implementación de tratamientos efectivos y métodos diagnósticos complejos, pasando por una atención “cat friendly” y libre de temor. Este manual proporciona conocimientos sólidos respaldados por la ciencia, combinados con consejos y experiencias prácticas y útiles de los autores, que harán que la atención médica del gato sea más comprensible y manejable. Este manual cuenta con figuras, vídeos, tablas, diagramas, gráficos y esquemas prácticos para que el veterinario clínico pueda usarlos y aplicarlos en su clínica diaria, donde no se pretende reemplazar la experiencia de un profesional veterinario, sino ser una guía práctica para comprender, prevenir y abordar los problemas de salud en los gatos.', '["medicina felina"]', 'active', '2025-10-15 23:18:01.565696+00'),
(10, 'Manual práctico de endocrinología clínica en el perro', 'Este libro de endocrinología aborda las enfermedades hormonales en el perro a través de una actualización realizada por numerosos expertos de renombre mundial en cada tema; y se complementa con evidencias extraídas de la consulta en la práctica diaria de los autores a través de interesantes y desafiantes casos clínicos.', 1, 'Santiago Teyssandier, Elber A. Soler Arias', '6f0a99abc34442e8f7764a2175b0bf1dc0a5f0d4c2ef85ff918ce9942cadcb21.webp', '17 x 24 cm', 592, 'tapa dura', '978-84-18636-27-1', 'Esta obra, además de reflejar los conceptos y avances de los expertos en endocrinología, tiene la ventaja de estar escrita en español, ya que los coautores han querido volcar en ella su trabajo, conocimientos y experiencia. Además de las enfermedades endocrinas clásicas, también se abordan situaciones excepcionales que han ido surgiendo en este apasionante mundo de la endocrinología. Todo ello, a través de una serie de imágenes, vídeos, tablas y algoritmos diagnósticos basados en la consulta endocrinológica diaria.', '["endocrinologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(11, 'Emergencias y cuidados críticos en el gato', 'En estas páginas el lector encontrará estrategias terapéuticas y los últimos avances en esta área que evoluciona rápidamente, todo diseñado para apoyar a profesionales que enfrentan los momentos más desafiantes de la práctica veterinaria, cuando atienden a estos pacientes.', 1, 'Javier Mouly, Pablo Donati', '088f16923b248c92374647d48e62326a5fa2856b8cb30bc0ffd8781ed53e0585.webp', '22 x 28 cm', 380, 'tapa dura', '978-84-18636-35-6', 'En estas páginas el lector encontrará estrategias terapéuticas y los últimos avances en esta área que evoluciona rápidamente, todo diseñado para apoyar a profesionales que enfrentan los momentos más desafiantes de la práctica veterinaria, cuando atienden a estos pacientes.', '["emergencias veterinarias", "cuidados criticos"]', 'active', '2025-10-15 23:18:01.565696+00'),
(12, 'Guía práctica de Medicina Interna perros, gatos y exóticos', 'El objeto de esta obra es la de presentar al clínico las claves para el diagnóstico y tratamiento de las principales afecciones que se presentan en la práctica habitual. Concebido para una consulta diaria fácil y rápida, para cada especie, perros, gatos, hurones, roedores, conejos, reptiles y aves la obra se divide en cuatro partes.', 1, 'Fabrice Hébert y Christophe Bulliot', 'e51db852b36e75dd65a3657e91743721653d74688b58538ca591beeb98434c8b.webp', '17 x 24 cm', 848, 'tapa dura', '978-84-124944-6-4', 'La primera es un diccionario con un total de 500 patologías o síndromes en las que se detallan introducción, etiología, síntomas, diagnóstico, tratamientos con dosis, pronóstico y complicaciones para cada condición. La segunda expone los abordajes diagnósticos y terapéuticos en forma de 80 valiosos algoritmos partiendo de los síntomas más frecuentes y siguiendo los mejores protocolos. La tercera presenta, en forma de 180 tablas, las posibles etiologías de las patologías o síndromes descritos. Una última parte detalla cómo realizar e interpretar las 70 principales técnicas o pruebas complementarias que puede requerir el clínico. Finalmente, el lector encontrará un útil recordatorio de los valores biológicos habituales, las normas ecocardiográficas y la posología de los principales medicamentos empleados en terapéutica de animales de compañía resumidas en 90 tablas. Esta edición permite además acceso a los vídeos de procedimientos técnicos gracias a los numerosos códigos QR.', '["medicina interna veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(13, 'Atlas de radiografía torácica por razas caninas', 'Este atlas de consulta rápida ayudará al clínico a obtener la máxima información de sus estudios radiográficos del tórax. Presenta gran cantidad de imágenes que guiarán al veterinario en su interpretación radiográfica, desde la misma técnica, la posición más idónea según la patología que se sospeche o el estado clínico del paciente, o variaciones fisiológicas, hasta el órgano o estructuras torácicas a evaluar.', 1, 'David Marbella Fernández - Almudena C. Pueyo Montes', 'e333dff94e14237b0001dab397b2e462d02f99bfee812e4badd789c175f2876f.webp', '22 x 28 cm', 128, 'tapa dura', '978-84-96344-62-4', 'Presenta montajes anatómico-radiográficos para ayudar a visualizar las estructuras que se están valorando en la radiografía. Aporta imágenes de las proyecciones radiográficas torácicas normales de más de 30 razas caninas para su comparación directa lo que hacen de este libro una guía de referencia de radiografías torácicas raciales.', '["radiologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(14, 'Manual de cirugía de tejidos blandos en pequeños animales, 2ª edición', 'En esta obra, la cirujana Karen Tobias se basa en sus más de dos decadas de experiencia para compartir consejos y trucos que los cirujanos experimentados utilizan para hacer más fácil, rápido y exitoso un procedimiento quirúrgico. Aporta instrucciones claras, concisas y paso a paso de como completar procedimientos comúnmente realizados en la clínica de pequeños animales, meticulosamente ilustradas con cientos de fotografías de alta definición y dibujos.', 1, 'Karen Tobías', 'c19efe3b6f5f54e2edb440c02c8ebad4f78af32e75a1f1f12e3520d15fbff2ae.webp', '22 x 28 cm', 358, 'tapa dura', '978-84-96344-90-7', 'Totalmente actualizada y revisada, esta segunda edición contiene una cobertura ampliada de los últimos avances y abordajes de técnicas quirúrgicas. Organizado por tipos de procedimiento, el libro cubre la cirugía de piel, abdomen, sistema digestivo, tracto reproductivo, peritoneo, cabeza y cuello, y procedimientos misceláneos. Cada capítulo contiene una introducción, consejos para el manejo preoperatorio, cirugía y técnicas quirúrgicas, y consideraciones postoperatorias.', '["cirugia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(15, 'Dermatología clínica en el perro y en el gato', 'El objetivo de esta obra ha sido revisar y condensar los conocimientos en dermatología clínica canina y felina de los últimos 20 años y plasmar en sus páginas la información más relevante y actualizada para los veterinarios clínicos de animales de compañía interesados en esta especialidad.', 1, 'Ana Ríos, Maite Verde, César Yotti', 'ba2ee15feaec53441cf4750f45c895056b0d27cc4645b2fb3be58efafa153474.webp', '22 x 28 cm', 780, 'tapa dura', '978-84-96344-98-3', 'El libro se organiza en tres secciones; en la primera se trata la anatomía de la piel, el microbioma cutáneo, la estructura de la consulta dermatológica y las pruebas diagnósticas más relevantes y novedosas, destacando la citología clínica en los procesos inflamatorios y el estudio histopatológico de la piel. En la segunda sección se plantean los principales problemas cutáneos a partir de un enfoque diagnóstico general teniendo en cuenta el tipo de lesión predominante y la especie afectada. En la tercera parte se describen las principales enfermedades de la piel: infecciosas, alérgicas, inmunomediadas, seborreicas, metabólicas, endocrinas y genéticas. Se ha dedicado un capítulo exclusivo a la dermatitis atópica, por el extraordinario desarrollo y relevancia de los conocimientos sobre su patogenia y tratamiento en los últimos años. También se ha intentado realizar una exposición detallada de los principales tumores cutáneos y de los hallazgos citológicos de los mismos, que permita al clínico reconocer y diagnosticar de la forma más precoz posible esta patología.', '["dermatologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(16, 'Manual clínico de farmacología y complicaciones en anestesia de pequeños animales. 2ª Edición', 'Este Manual clínico de farmacología y complicaciones en anestesia de pequeños animales busca ser una obra de consulta rápida para el veterinario en lo referente al manejo de los fármacos más utilizados en anestesia, así como de las principales complicaciones con las que nos podemos encontrar durante el periodo perioperatorio.', 1, 'M. A. Cabezas Salamanca, I. Sández Cordero', '1d1ad8c578c32e1f029635595612909242874a87a7657be85f89f26bba0caa63.webp', '17 x 24 cm', 280, 'tapa dura', '978-84-96344-06-8', 'Esta guía está basada en la bibliografía más reciente y en la experiencia clínica de los autores y está dividida en dos grandes bloques: el primero es un listado de fármacos, con sus características más importantes y dosificación y en el que se incluyen comentarios clínicos de los autores; en un segundo bloque se presentan las principales complicaciones que nos podemos encontrar, sus causas, consecuencias y tratamiento de una forma sencilla y práctica.', '["farmacologia", "anestesia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(17, 'Manual de ventilación mecánica en pequeños animales', 'Este manual práctico en ventilación mecánica en pequeños animales está basado en una recopilación de cursos, artículos y textos de medicina humana y veterinaria aplicados gracias a la propia experiencia por parte de los autores en la materia. Pretende que el veterinario clínico pueda entender e interpretar correctamente la ventilación mecánica en los diferentes procedimientos quirúrgicos que lo requieran y en diferentes situaciones clínicas.', 1, 'Jerónimo Martínez Pino', 'f88b77d2a1cbf96f7935fbfda8523e846be5baa1c012e9abb9f2d0817626ed71.webp', '17 x 24 cm', 176, 'tapa dura', '978-84-96344-78-5', 'El libro comienza con un capítulo de fisiología respiratoria aplicada básica para el entendimiento de la ventilación espontánea y mecánica. Se tratan todos los temas fundamentales para poder empezar a ventilar correctamente, poder entender el funcionamiento de una estación de anestesia desde los aspectos más básicos a los más actuales, programar cualquier modo ventilatorio e interpretar la monitorización respiratoria en cualquier situación clínica. Además, el veterinario podrá encontrar cómo utilizar correctamente la VM en diferentes situaciones clínicas donde se transforma en una herramienta fundamental para el éxito. Por último, el lector encontrará una breve revisión de las complicaciones asociadas a la ventilación mecánica y un capítulo final sobre el uso de la ecografía como herramienta para el diagnóstico de diferentes situaciones pulmonares de nuestros pacientes.', '["ventilacion mecanica", "anestesia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(18, 'Morfología de células normales en citología canina y felina', 'Morfología normal de las células en citología canina y felina realiza un abordaje visual único a la identificación de las células normales en perros y gatos. Las presentaciones en una única página ofrecen instantáneas de los tipos celulares individualmente, con microfotografías de alta calidad emparejadas con diagramas y texto descriptivo.', 1, 'Lorenzo Ressel', 'b09676cda4ada68f2066b7f718d90688865f73cc41960918be9efa35ce0a6f5f.webp', '15 x 21 cm', 200, 'rustica', '978-84-96344-75-4', 'El libro empieza con una introducción concisa de los principios de la identificación morfológica, seguida de la descripción de la distribución de las células y de donde se pueden obtener los diferentes tipos de células en los distintos tejidos y órganos. La parte principal del libro está dedicado a describir cada tipo de célula y sus características. También se describen citoarquitecturas, material no celular observado y cambios patológicos generales.', '["citologia veterinaria", "morfologia celular"]', 'active', '2025-10-15 23:18:01.565696+00'),
(19, 'Manual práctico de enfermedades infecciosas y parasitarias del perro', 'Manual práctico de enfermedades infecciosas y parasitarias en el perro es una herramienta práctica para el veterinario, abordando desde diferentes perspectivas estas patologías. El hilo conductor es un recorrido desde la práctica diaria hasta las últimas actualizaciones de cada tema abordado.', 1, 'Pablo Borrás', '1d41c7bd791fdf82e45c5760007748944607230ea78a92112a8216cd97a55ded.webp', '17 x 24 cm', 628, 'tapa dura', '978-84-18636-24-0', 'La obra está dividida en dos secciones: la primera sección se basa en el estudio de casos clínicos de diferentes entidades infecciosas y parasitarias que afectan a los perros. Después de cada caso clínico, el lector encontrará una revisión práctica y actualizada sobre la enfermedad en cuestión, así como los puntos clave. Se abordarán diferentes enfermedades producidas por virus, bacterias, hongos, protozoarios y helmintos. La segunda sección cuenta con diferentes capítulos escritos por expertos de diferentes partes del mundo sobre temas claves de infectología canina. Se abordarán distintas problemáticas con una mirada actualizada y basada en sólidas evidencias científicas, proveyendo herramientas al veterinario para su consulta diaria.', '["infectologia canina", "parasitologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(20, 'Diagnóstico ultrasonográfico en perros, gatos y mamíferos exóticos', 'Una colección de más de 2000 imágenes y una videoteca de 900 clips que permiten al profesional acceder a una obra de consulta ágil y completa. 41 autores de prestigio han participado en la elaboración de este libro, dándole un enfoque clínico, más accesible y didáctico.', 1, 'Hernán Fominaya', 'cf20a3ebcbf14c2159693ec83fdd4822d023b964585318ad9aa40d81b75e8f69.webp', '22 x 28 cm', 736, 'tapa dura', '978-84-18636-25-7', 'Un temario completo: ecografía abdominal, pulmonar, ecocardiografía, musculoesquelético, con capítulos específicos sobre la aplicación del Doppler vascular, ecografía felina y de otras especies menores, ecografía transcraneana, ocular, cervical o ecografía enfocada al servicio de urgencias y cuidados críticos. Todo ello hace de esta una obra completa a la que el lector podrá recurrir para profundizar en el estudio y poder avanzar en la técnica de diagnóstico por ultrasonido en su práctica diaria.', '["diagnostico por imagen", "ultrasonografia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(21, 'Manual de cardiología canina y felina', 'El Manual de cardiología canina y felina, en su quinta edición, ha sido actualizado para seguir satisfaciendo la necesidad de un libro que aporte información útil y práctica en enfermedades cardíacas en el perro y el gato.', 1, 'Francis W. K. Smith, Jr., Larry P. Tilley, Mark A. Oyama, Meg M. Sleeper', 'c162eb7ce97f9a64d00f5ae2ebb8bd326648b855511d66f2c852bc38232a547e.webp', '22 x 28 cm', 472, 'tapa dura', '978-84-96344-63-1', 'Desde la cuarta edición de este libro, se ha producido un tremendo crecimiento en el campo de la cardiología canina y felina. La quinta edición ha sido cuidadosamente revisada, editada, y actualizada y también tiene una generosa cantidad de figuras y cuadros nuevos, con la mayoría en color. El nuevo material incluye un nuevo capítulo de cirugía cardíaca, un nuevo capítulo de terapia con marcapasos, un nuevo capítulo de pruebas genéticas y con biomarcadores en enfermedades cardíacas, un nuevo capítulo de nutrición y enfermedades cardiovasculares y una tabla de predilecciones raciales en perros y gatos para enfermedades cardíacas en el apéndice 1.', '["cardiologia veterinaria"]', 'active', '2025-10-15 23:18:01.565696+00'),
(22, 'Prueba Pos-Entrega', '', 5000, 'Tomás', '68d0753c3503b41466c3a767467b1ba9d394c7fc84197178126ceb4d82109e20.png', '', 10, 'No', '123A-4567B-890C', '', '[]', 'inactive', '2025-10-17 22:58:06.59+00');
